def display_awards(awards_dict):
    for award, year in awards_dict.items():
        print(f"{award}: {year}")

# Example usage:
awards = {
    "National Film Award for Best Music Direction": 1975,
    "Padma Shri": 1977,
    "Dada Saheb Phalke Award": 1992,
    "Padma Bhushan": 2001,
    "Sangeet Natak Akademi Fellowship": 2008
}
display_awards(awards)
